use serde::{Serialize, Deserialize};

#[derive(Serialize, Deserialize, Clone, Debug)]
pub struct MultiplayerConfig {
    pub players_per_game: usize,
    pub enabled: bool,
    pub autostart_after_s: u64,
    #[serde(default = "default_net_conf")]
    pub network: NetworkConf,
    #[serde(default = "default_fake_users")]
    pub fakes: Vec<FakePlayerConf>,
    #[serde(default = "default_ba_conf")]
    pub battle_arena: BattleArenaConfig,
    #[serde(default = "default_pit_conf")]
    pub pit_config: PitConfig,
    #[serde(default = "default_tdm_conf")]
    pub team_death_match: TeamDeathMatchConfig,
}

impl super::config::SelfValidator for MultiplayerConfig {
    type Context = crate::ConfigImpl;
    fn validate(&self, info: &mut super::config::ValidationInfo, _ctx: &Self::Context) -> bool {
        let mut is_ok = true;
        if !self.enabled {
            info.info(super::config::ValidationMessage {
                path: vec!["enabled".to_owned()],
                message: "Multiplayer is disabled so validation is skipped".to_owned(),
            });
            return true;
        }
        if self.players_per_game == 0 {
            info.error(super::config::ValidationMessage {
                path: vec!["players_per_game".to_owned()],
                message: "Game match must have at least one player to start".to_owned(),
            });
            is_ok = false;
        } else if self.players_per_game == 1 {
            info.warn(super::config::ValidationMessage {
                path: vec!["players_per_game".to_owned()],
                message: "Game match may be lonely with only one player".to_owned(),
            });
        }
        if ((self.players_per_game as f32) / (self.fakes.len() as f32)) > 1.0 {
            info.warn(super::config::ValidationMessage {
                path: vec!["fakes".to_owned()],
                message: "Game match may have broken vehicle flipping functionality due to more than 1 ClientAI per player".to_owned(),
            });
        }
        // TODO
        is_ok
    }
}

#[derive(Serialize, Deserialize, Clone, Debug)]
pub struct NetworkConf {
    pub network_channel_ty: String,
    pub max_sent_message_queue_size: u16,
    pub is_acks_long: bool,
    pub network_drop_threshold: u8,
    pub packet_size: u16,
    pub max_combined_reliable_message_count: u16,
    pub max_combined_reliable_message_size: u16,
    pub min_update_timeout: u16,
    pub max_delay: i64,
    pub overflow_threshold: u8,
    pub max_packet_size: u16,
    pub resend_delay_base: f64,
    pub resend_delay_rtt_mult: f64,
    pub network_peer_update_interval: i32,
    pub max_delay_for_disconnect_ms: i32,
}

pub(super) fn default_net_conf() -> NetworkConf {
    NetworkConf {
        network_channel_ty: "3113".to_owned(),
        max_sent_message_queue_size: 64,
        is_acks_long: true,
        network_drop_threshold: 80,
        packet_size: 1200,
        max_combined_reliable_message_count: 20,
        max_combined_reliable_message_size: 200,
        min_update_timeout: 1,
        max_delay: 1,
        overflow_threshold: 10,
        //max_packet_size: 5888,
        max_packet_size: 1024,
        resend_delay_base: 0.1,
        resend_delay_rtt_mult: 0.5,
        network_peer_update_interval: 1,
        max_delay_for_disconnect_ms: 1000,
    }
}

