#[derive(Serialize, Deserialize, Clone, Debug)]
#[serde(tag = "impl")]
pub enum ClientEmulation {
    Experimental,
    ClientAI,
}

impl ClientEmulation {
    pub(super) fn to_config(self) -> super::config::ClientEmulator {
        match self {
            Self::Experimental => super::config::ClientEmulator::Experiment,
            Self::ClientAI => super::config::ClientEmulator::ClientAI,
        }
    }
}

#[derive(Serialize, Deserialize, Clone, Debug)]
pub struct BattleArenaConfig {
    #[serde(default = "default_crystal_health")]
    pub crystal_health: u32,
    #[serde(default = "default_respawn_time")]
    pub respawn_time_s: u64,
    #[serde(default = "default_equalizer")]
    pub equalizer: super::garage::PrefabVehicle,
    #[serde(default = "default_equalizer_health")]
    pub equalizer_health: u64,
    pub equalizer_trigger_time_s: Option<u64>,
    #[serde(default = "default_equalizer_warning")]
    pub equalizer_warning_s: u64,
    #[serde(default = "default_equalizer_duration")]
    pub equalizer_duration_s: u64,
    #[serde(default = "default_ba_base")]
    pub base: super::garage::PrefabVehicle,
    #[serde(default = "default_segments")]
    pub num_segments: u16,
}

pub(super) fn default_ba_conf() -> BattleArenaConfig {
    BattleArenaConfig {
        crystal_health: default_crystal_health(),
        respawn_time_s: default_respawn_time(),
        equalizer: default_equalizer(),
        equalizer_health: default_equalizer_health(),
        equalizer_trigger_time_s: None,
        equalizer_warning_s: default_equalizer_warning(),
        equalizer_duration_s: default_equalizer_duration(),
        base: default_ba_base(),
        num_segments: default_segments(),
    }
}

